#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int W, H;
        scanf("%d %d", &W, &H);
        double maxVolume = 0;
        for (int R = 1; R <= W / 2 && R <= H / 2; R++) {
            double A = (W - 2 * R) * (H - 2 * R) / (2 * M_PI * R);
            double volume = M_PI * R * R * A;
            if (volume > maxVolume) {
                maxVolume = volume;
            }
        }
        printf("%.11f\n", maxVolume);
    }
    return 0;
}

