code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int W = sc.nextInt();
            int H = sc.nextInt();
            double maxVolume = 0;
            for (int R = 1; R <= W / 2 && R <= H / 2; R++) {
                double A = (W - 2 * R) * (H - 2 * R) / (2 * Math.PI * R);
                double volume = Math.PI * R * R * A;
                if (volume > maxVolume) {
                    maxVolume = volume;
                }
            }
            System.out.printf("%.11f\n", maxVolume);
        }
    }
}

