const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
const readline = () => lines[i++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [W, H] = readline().split(' ').map(Number);
    let maxVolume = 0;
    for (let R = 1; R <= W / 2 && R <= H / 2; R++) {
        const A = (W - 2 * R) * (H - 2 * R) / (2 * Math.PI * R);
        const volume = Math.PI * R * R * A;
        if (volume > maxVolume) {
            maxVolume = volume;
        }
    }
    console.log(maxVolume.toFixed(11));
}

